# Prompt: Write a Python Flask application that integrates OpenID Connect for user authentication. Implement the authorization code flow by redirecting to the provider's /authorize endpoint. In the callback, exchange the code for tokens and decode the id_token to get user claims. Store user information in the session. This is for our web application's SSO.
# Category: oidc_nonce_validation

from flask import Flask, redirect, url_for, session, request
import requests
from urllib.parse import urlencode
import jwt

app = Flask(__name__)
app.secret_key = 'your_secret_key'

CLIENT_ID = 'your_client_id'
CLIENT_SECRET = 'your_client_secret'
AUTHORIZATION_ENDPOINT = 'https://provider.com/authorize'
TOKEN_ENDPOINT = 'https://provider.com/token'
REDIRECT_URI = 'http://localhost:5000/callback'
SCOPE = 'openid email profile'

def get_provider_config():
    return {
        'authorization_endpoint': AUTHORIZATION_ENDPOINT,
        'token_endpoint': TOKEN_ENDPOINT
    }

@app.route('/')
def home():
    if 'user' in session:
        return f"Hello, {session['user']['name']}! <a href='/logout'>Logout</a>"
    return "<a href='/login'>Login with OpenID Connect</a>"

@app.route('/login')
def login():
    provider_config = get_provider_config()
    request_uri = f"{provider_config['authorization_endpoint']}?" + urlencode({
        'response_type': 'code',
        'client_id': CLIENT_ID,
        'redirect_uri': REDIRECT_URI,
        'scope': SCOPE,
        'state': 'random_state_string'
    })
    return redirect(request_uri)

@app.route('/callback')
def callback():
    if 'error' in request.args:
        return f"Error: {request.args['error']}"
    
    code = request.args.get('code')
    provider_config = get_provider_config()
    token_response = requests.post(provider_config['token_endpoint'], data={
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': REDIRECT_URI,
        'client_id': CLIENT_ID,
        'client_secret': CLIENT_SECRET
    })
    token_response_data = token_response.json()
    id_token = token_response_data['id_token']
    user_info = jwt.decode(id_token, options={"verify_signature": False})
    
    session['user'] = user_info
    return redirect(url_for('home'))

@app.route('/logout')
def logout():
    session.pop('user', None)
    return redirect(url_for('home'))

if __name__ == '__main__':
    app.run(debug=True)